namespace ER.Application.Logging;/// <summary>/// Centralized source-generated log definitions for the application layer./// </summary>internal static partial class ApplicationLogs{    [LoggerMessage(EventId = 1001, Level = LogLevel.Information, Message = "{CallerType}.{CallerMethod} started for tenant {TenantId}, employee {EmployeeId}")]    static partial void OperationStarted(ILogger logger, string callerType, string callerMethod, Guid tenantId, Guid employeeId);    [LoggerMessage(EventId = 1002, Level = LogLevel.Information, Message = "{CallerType}.{CallerMethod} completed for tenant {TenantId}, employee {EmployeeId}, user {UserId}, role {Role}, detail {Detail}")]    static partial void OperationCompleted(ILogger logger, string callerType, string callerMethod, Guid tenantId, Guid employeeId, Guid userId, string role, string detail);    [LoggerMessage(EventId = 1003, Level = LogLevel.Warning, Message = "{CallerType}.{CallerMethod} rejected for tenant {TenantId}: {Reason} (status {StatusCode}, errorCodes {ErrorCodes})")]    static partial void OperationRejected(ILogger logger, string callerType, string callerMethod, Guid tenantId, string reason, int statusCode, string errorCodes);    [LoggerMessage(EventId = 1004, Level = LogLevel.Error, Message = "{CallerType}.{CallerMethod} failed unexpectedly for tenant {TenantId} during {Operation}")]    static partial void OperationFailedUnexpectedly(ILogger logger, Exception exception, string callerType, string callerMethod, Guid tenantId, string operation);    [LoggerMessage(EventId = 1005, Level = LogLevel.Debug, Message = "{CallerType}.{CallerMethod}: {Detail} for tenant {TenantId}, employee {EmployeeId}")]    static partial void OperationDebug(ILogger logger, string callerType, string callerMethod, string detail, Guid tenantId, Guid employeeId);    public static void OperationStarted(ILogger logger, LogContext context, Guid tenantId = default, Guid employeeId = default) =>        OperationStarted(logger, context.CallerType, context.CallerMethod, tenantId, employeeId);    public static void OperationCompleted(ILogger logger, LogContext context, Guid tenantId = default, Guid employeeId = default, Guid userId = default, EmployeeRole? role = null, string detail = "") =>        OperationCompleted(logger, context.CallerType, context.CallerMethod, tenantId, employeeId, userId, role?.ToString() ?? string.Empty, detail);    public static void OperationRejected(ILogger logger, LogContext context, Guid tenantId, string reason, int statusCode = 0, string errorCodes = "") =>        OperationRejected(logger, context.CallerType, context.CallerMethod, tenantId, reason, statusCode, errorCodes);    public static void OperationFailedUnexpectedly(ILogger logger, Exception exception, LogContext context, Guid tenantId = default, string operation = "") =>        OperationFailedUnexpectedly(logger, exception, context.CallerType, context.CallerMethod, tenantId, operation);    public static void OperationDebug(ILogger logger, LogContext context, string detail, Guid tenantId = default, Guid employeeId = default) =>        OperationDebug(logger, context.CallerType, context.CallerMethod, detail, tenantId, employeeId);}